import React from 'react';
import {
  FaFacebookF,
  FaInstagram,
  FaTwitter,
  FaYoutube,
  FaPhone,
  FaEnvelope
} from 'react-icons/fa';
import { MdEmail } from 'react-icons/md';

const TopBar = () => {
  return (
    <div className="bg-primary text-white py-2 px-3">
      <div className="container-fluid">
        <div className="row align-items-center justify-content-between text-center text-md-start">
          {/* Left side */}
          <div className="col-md-auto mb-2 mb-md-0">
            <span className="me-3">
              <FaEnvelope className="me-1" />
              principle@bramaasschool.com
            </span>
            <span className="vr mx-2 d-none d-md-inline"></span>
            <span>
              <FaPhone className="me-1" />
              +95667 95556 / +95667 955566
            </span>
          </div>

          {/* Right side */}
          <div className="col-md-auto">
            <span className="me-2">
              <FaFacebookF className="me-2" />
              <FaInstagram className="me-2" />
              <FaTwitter className="me-2" />
              <FaYoutube className="me-2" />
              <MdEmail className="me-2" />
              <FaPhone className="me-2" />
            </span>
            <span className="ms-2 border-start ps-2">Online Payment</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TopBar;
